import { fileTypeFromBuffer } from 'file-type';
const ALLOWED = new Set(['image/png', 'image/jpeg']);
app.post('/upload', upload.single('file'), async (req, res) => {
  if (req.file.size > 5 * 1024 * 1024) return res.status(413).send('too large');
