import magic, uuid, os
ALLOWED = {'image/png': '.png', 'application/pdf': '.pdf'}
@app.post('/upload')
def upload():
    f = request.files['file']
    head = f.stream.read(2048); f.stream.seek(0)
    mime = magic.from_buffer(head, mime=True)
    if mime not in ALLOWED:
        return {'error': 'unsupported type'}, 400
    name = uuid.uuid4().hex + ALLOWED[mime]
    save_path = os.path.join(UPLOAD_DIR, name)
    f.save(save_path)
    return {'saved': name}

